func:
// Topic format:
// <room>/<type>/<field> (where <type> is data or control)

var parts = msg.topic.split("/");
if (parts.length !== 3) {
    return null;
}

var room = parts[0];
var type = parts[1];
var field = parts[2];

if (type !== "data" && type !== "control") {
    node.warn("Unknown type: " + type);
    return null;
}

// Map the field name to standard base field
let baseField = field;
if (field === "led_data") baseField = "led";
else if (field === "ac_data") baseField = "ac";
else if (field === "projector_data") baseField = "projector";

// Set measurement name dynamically based on type (data or control)
msg.measurement = "classroom_" + type;

const stringFields = ["ac", "status", "command"];
const intFields = [
    "active",
    "alert",
    "co2",
    "human",
    "led",
    "lux",
    "projector",
    "led_data",
    "ac_data",
    "projector_data"
];
const floatFields = ["temp"];

var value;

if (intFields.includes(field)) {
    value = parseInt(msg.payload, 10);
    if (isNaN(value)) return null;
    value = value.toString() + "i";
}
else if (floatFields.includes(field)) {
    value = parseFloat(msg.payload);
    if (isNaN(value)) return null;
}
else if (stringFields.includes(field)) {
    if (field === "status" || field === "command") {
        let parsed = parseInt(msg.payload, 10);
        if (!isNaN(parsed) && String(parsed) === String(msg.payload).trim()) {
            value = parsed.toString() + "i";
        } else {
            value = String(msg.payload);
        }
    } else {
        value = String(msg.payload);
    }
}
else {
    node.warn("Unknown field: " + field);
    return null;
}

msg.payload = [
    {
        [baseField]: value
    },
    {
        room: room
    }
];

return msg;

let row = msg.payload;

msg.topic =

    row.room +
    "/control/" +
    row._field;

msg.payload = String(row._value);

return msg;

let row = msg.payload;

msg.topic =

    row.room +
    "/control/schedule";

msg.payload = String(row._value);

return msg;

const days = [
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday"
];

msg.payload = days[new Date().getDay()];
return msg;

// Extract the raw status text from the node
let mqttState = msg.status.text;

// Map the text to integers
if (mqttState === "node-red:common.status.connected") {
    msg.payload = 2; 
} else if (mqttState === "node-red:common.status.connecting") {
    msg.payload = 1;
} else {
    // This catches "disconnected", "error", or any other failure state
    msg.payload = 0; 
}

return msg;

let roomsState = flow.get("roomsState") || {};
let now = Date.now();

Object.keys(roomsState).forEach(roomName => {
    let r = roomsState[roomName];
    let elapsed = now - r.lastSeen;

    if (elapsed > 300000) {
        r.status = -1;
        r.led_data = -1;
        r.ac_data = -1;
        r.projector_data = -1;
    } else {
        r.status = r.active === 1 ? 1 : 0;
    }
});

let msgRooms = {
    topic: "rooms",
    payload: Object.values(roomsState)
};
let msgLed = {
    payload: 1
};
return [msgRooms, msgLed];

if (msg.topic === "control") {
    let payload = msg.payload;
    let room = payload.room;
    let device = payload.device;
    let value = payload.value;

    let msgMqtt = {
        topic: room + "/control/" + device,
        payload: String(value)
    };

    let msgInflux = {
        measurement: "classroom_control",
        payload: [
            { [device]: value },
            { room: room }
        ]
    };

    return [msgMqtt, msgInflux, null];
} 
else if (msg.topic === "get_history") {
    let room = msg.payload.room;
    let start = msg.payload.start;
    let stop = msg.payload.stop;
    let range = msg.payload.range;
    let window = msg.payload.window;

    let rangePart = '';
    if (start && stop) {
        rangePart = `|> range(start: ${start}, stop: ${stop})`;
    } else if (range) {
        rangePart = `|> range(start: -${range})`;
    } else {
        rangePart = `|> range(start: -24h)`;
    }

    let aggPart = '';
    if (window && window !== 'none') {
        aggPart = `\n  |> aggregateWindow(every: ${window}, fn: mean, createEmpty: false)`;
    }

    let msgQuery = {
        payload: room,
        query: `from(bucket: "SmartClass")
  ${rangePart}
  |> filter(fn: (r) => r.room == "${room}")
  |> filter(fn: (r) => r._measurement == "classroom")
  |> filter(fn: (r) => r._field == "temp" or r._field == "lux" or r._field == "co2")${aggPart}`
    };

    return [null, null, msgQuery];
}

return null;

if (!Array.isArray(msg.payload)) {
    return null;
}

let records = msg.payload;
let room = records.length > 0 ? records[0].room : "";

let historyData = {
    temp: [],
    lux: [],
    co2: []
};

records.forEach(row => {
    let field = row._field;
    let value = parseFloat(row._value);
    let time = new Date(row._time).getTime();

    if (field === "temp" || field === "temperature") {
        historyData.temp.push({ x: time, y: value });
    } else if (field === "lux") {
        historyData.lux.push({ x: time, y: value });
    } else if (field === "co2") {
        historyData.co2.push({ x: time, y: value });
    }
});

historyData.temp.sort((a, b) => a.x - b.x);
historyData.lux.sort((a, b) => a.x - b.x);
historyData.co2.sort((a, b) => a.x - b.x);

msg.topic = "history";
msg.room = room;
msg.payload = historyData;

return msg;

if (msg.topic === "select_room") {
    let room = msg.payload;
    flow.set("selectedRoom", room);

    let msgNavigate = {
        payload: {
            page: "Classroom Detail"
        }
    };

    let roomsState = flow.get("roomsState") || {};
    let roomState = roomsState[room] || {
        room: room,
        temp: "-",
        lux: "-",
        co2: "-",
        led_data: 0,
        ac_data: 0,
        projector_data: 0,
        ac_temp: 24,
        active: 0
      };

    let msgState = {
        topic: "room_state",
        payload: roomState
    };

    let msgHistoryQuery = {
        topic: "get_history",
        payload: {
            room: room,
            range: "24h",
            window: "none"
        }
    };

    return [[msgNavigate, msgState], null, msgHistoryQuery, null];
}

if (msg.topic === "detail_mounted") {
    let room = flow.get("selectedRoom");
    if (!room) {
        return [
            { payload: { page: "Home Page" } },
            null,
            null,
            null
        ];
    }

    let msgInit = {
        topic: "init_room",
        payload: {
            room: room
        }
    };

    let roomsState = flow.get("roomsState") || {};
    let roomState = roomsState[room] || {
        room: room,
        temp: "-",
        lux: "-",
        co2: "-",
        led_data: 0,
        ac_data: 0,
        projector_data: 0,
        ac_temp: 24,
        active: 0
    };

    let msgState = {
        topic: "room_state",
        payload: roomState
    };

    let msgHistoryQuery = {
        topic: "get_history",
        payload: {
            room: room,
            range: "24h",
            window: "none"
        }
    };

    return [[msgInit, msgState], null, msgHistoryQuery, null];
}

if (msg.topic === "control") {
    return [null, null, null, msg];
}

if (msg.topic === "get_history") {
    return [null, null, null, msg];
}

if (msg.topic === "go_back") {
    flow.set("selectedRoom", null);
    let msgNavigate = {
        payload: {
            page: "Home Page"
        }
    };
    return [msgNavigate, null, null, null];
}

return null;

let roomsState = flow.get("roomsState") || {};

let parts = msg.topic.split("/");
if (parts.length === 3) {
    let room = parts[0];
    let type = parts[1];
    let field = parts[2];

    if (type === "data" || type === "control") {
        if (!roomsState[room]) {
            roomsState[room] = {
                room: room,
                lastSeen: Date.now(),
                temp: "-",
                lux: "-",
                co2: "-",
                human: 0,
                alert: 0,
                active: 0,
                led_data: 0,
                ac_data: 0,
                projector_data: 0,
                ac_temp: 24,
                ac_fan: "00",
                ac_swing: "00",
                status: 0,
                lastSeenTemp: 0,
                lastSeenLux: 0,
                lastSeenCo2: 0,
                lastSeenActive: 0,
                lastSeenLed: 0,
                lastSeenAc: 0,
                lastSeenProjector: 0
            };
        }

        roomsState[room].lastSeen = Date.now();

        let val = msg.payload;
        if (field === "temp" || field === "temperature") {
            roomsState[room].temp = parseFloat(val).toFixed(1);
            roomsState[room].lastSeenTemp = Date.now();
        } else if (field === "lux") {
            roomsState[room].lux = parseInt(val, 10);
            roomsState[room].lastSeenLux = Date.now();
        } else if (field === "co2") {
            roomsState[room].co2 = parseInt(val, 10);
            roomsState[room].lastSeenCo2 = Date.now();
        } else if (field === "human") {
            roomsState[room].human = parseInt(val, 10);
            roomsState[room].active = roomsState[room].human === 1 ? 1 : 0;
            roomsState[room].status = roomsState[room].active === 1 ? 1 : 0;
            roomsState[room].lastSeenActive = Date.now();
        } else if (field === "alert") {
            roomsState[room].alert = parseInt(val, 10);
        } else if (field === "led_data" || field === "led") {
            roomsState[room].led_data = parseInt(val, 10);
            roomsState[room].lastSeenLed = Date.now();
        } else if (field === "ac_data" || field === "ac") {
            let strVal = String(val);
            if (strVal.length === 8) {
                let power = strVal.substring(0, 2);
                let temp = parseInt(strVal.substring(2, 4), 10);
                let fan = strVal.substring(4, 6);
                let swing = strVal.substring(6, 8);
                roomsState[room].ac_data = power === "01" ? 1 : 0;
                if (!isNaN(temp)) {
                    roomsState[room].ac_temp = temp;
                }
                roomsState[room].ac_fan = fan;
                roomsState[room].ac_swing = swing;
            } else {
                roomsState[room].ac_data = parseInt(val, 10);
            }
            roomsState[room].lastSeenAc = Date.now();
        } else if (field === "projector_data" || field === "projector") {
            roomsState[room].projector_data = parseInt(val, 10);
            roomsState[room].lastSeenProjector = Date.now();
        }

        flow.set("roomsState", roomsState);
    }
}

let selectedRoom = flow.get("selectedRoom");
if (selectedRoom) {
    let room = parts[0];
    let type = parts[1];
    let field = parts[2];

    if (room === selectedRoom && type === "data") {
        let outField = field;
        let outVal = msg.payload;

        if (field === "human") {
            outField = "active";
            outVal = parseInt(msg.payload, 10) === 1 ? 1 : 0;
        }

        msg.payload = {
            field: outField,
            value: outVal
        };
        msg.topic = "live_data";
        return msg;
    }
}
return null;
